function report_scalar(mysqli $conn,string $sql,string $types='',array $params=[]){$stmt=$conn->prepare($sql);if(!$stmt)return 0;if($types!=='')$stmt->bind_param($types,...$params);$stmt->execute();$row=$stmt->get_result()->fetch_row();$stmt->close();return $row[0]??0;}
function report_rows(mysqli $conn,string $sql,string $types='',array $params=[]):array{$stmt=$conn->prepare($sql);if(!$stmt)return[];if($types!=='')$stmt->bind_param($types,...$params);$stmt->execute();$rows=[];$r=$stmt->get_result();while($x=$r->fetch_assoc())$rows[]=$x;$stmt->close();return$rows;}
$summary=[
 'pinjam'=>(int)report_scalar($conn,'SELECT COUNT(*) FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id WHERE p.tanggal_pinjam BETWEEN ? AND ?','ss',[$from,$to]),
 'kembali'=>(int)report_scalar($conn,"SELECT COUNT(*) FROM perpus_peminjaman_detail WHERE DATE(tanggal_kembali) BETWEEN ? AND ? AND status<>'dipinjam'",'ss',[$from,$to]),
