 'dibayar'=>(float)report_scalar($conn,'SELECT COALESCE(SUM(nominal),0) FROM perpus_denda_pembayaran WHERE DATE(created_at) BETWEEN ? AND ?','ss',[$from,$to]),
 'reservasi'=>(int)report_scalar($conn,'SELECT COUNT(*) FROM perpus_reservasi WHERE DATE(tanggal_reservasi) BETWEEN ? AND ?','ss',[$from,$to]),
