 $rows=report_rows($conn,"SELECT b.id,b.judul,COUNT(d.id) jumlah,(SELECT COUNT(*) FROM perpus_buku_eksemplar e WHERE e.buku_id=b.id AND e.status='tersedia') tersedia FROM perpus_buku b JOIN perpus_peminjaman_detail d ON d.buku_id=b.id JOIN perpus_peminjaman p ON p.id=d.peminjaman_id WHERE p.tanggal_pinjam BETWEEN ? AND ? GROUP BY b.id,b.judul ORDER BY jumlah DESC,b.judul LIMIT 20",'ss',[$from,$to]);
