 $title='Laporan Sirkulasi';$description='Rincian peminjaman, pengembalian, keterlambatan, dan kondisi koleksi.';$where="p.tanggal_pinjam BETWEEN ? AND ?";$params=[$from,$to];$types='ss';if($q!==''){$where.=" AND (b.judul LIKE ? OR e.barcode LIKE ? OR a.nomor_anggota LIKE ? OR a.legacy_nama LIKE ?)";$like='%'.$q.'%';$params=array_merge($params,[$like,$like,$like,$like]);$types.='ssss';}$rows=report_rows($conn,"SELECT d.id,p.tanggal_pinjam,d.tanggal_jatuh_tempo,d.tanggal_kembali,d.status,d.kondisi_kembali,d.denda,d.denda_status,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul,e.barcode FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id JOIN perpus_anggota a ON a.id=p.anggota_id LEFT JOIN perpus_buku b ON b.id=d.buku_id LEFT JOIN perpus_buku_eksemplar e ON e.id=d.eksemplar_id WHERE $where ORDER BY p.tanggal_pinjam DESC,d.id DESC LIMIT 500",$types,$params);foreach($rows as &$r)$r['profile']=sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)($r['pemilik_id']??0),$r);unset($r);
}elseif($report==='koleksi'){
 $title='Laporan Koleksi';$description='Ketersediaan, kondisi, lokasi, dan tingkat pemanfaatan koleksi.';$rows=report_rows($conn,"SELECT b.id,b.judul,b.isbn,b.tahun_terbit,k.nama kategori,t.nama tipe,COUNT(e.id) eksemplar,COALESCE(SUM(e.status='tersedia'),0) tersedia,COALESCE(SUM(e.status='dipinjam'),0) dipinjam,COALESCE(SUM(e.status='rusak'),0) rusak,COALESCE(SUM(e.status='hilang'),0) hilang,COALESCE((SELECT COUNT(*) FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id WHERE d.buku_id=b.id AND p.tanggal_pinjam BETWEEN ? AND ?),0) pemakaian FROM perpus_buku b LEFT JOIN perpus_kategori_buku k ON k.id=b.kategori_id LEFT JOIN perpus_tipe_koleksi t ON t.id=b.tipe_koleksi_id LEFT JOIN perpus_buku_eksemplar e ON e.buku_id=b.id AND e.status<>'nonaktif' GROUP BY b.id,b.judul,b.isbn,b.tahun_terbit,k.nama,t.nama ORDER BY pemakaian DESC,b.judul LIMIT 500",'ss',[$from,$to]);
}elseif($report==='anggota'){
 $title='Laporan Anggota';$description='Keanggotaan, aktivitas peminjaman, keterlambatan, dan kunjungan.';$rows=report_rows($conn,"SELECT a.*,tm.nama tipe_member,(SELECT COUNT(d.id) FROM perpus_peminjaman p JOIN perpus_peminjaman_detail d ON d.peminjaman_id=p.id WHERE p.anggota_id=a.id AND p.tanggal_pinjam BETWEEN ? AND ?) jumlah_pinjam,(SELECT COUNT(d.id) FROM perpus_peminjaman p JOIN perpus_peminjaman_detail d ON d.peminjaman_id=p.id WHERE p.anggota_id=a.id AND d.status='dipinjam') aktif,(SELECT COUNT(d.id) FROM perpus_peminjaman p JOIN perpus_peminjaman_detail d ON d.peminjaman_id=p.id WHERE p.anggota_id=a.id AND d.status='dipinjam' AND d.tanggal_jatuh_tempo<CURDATE()) terlambat,(SELECT COUNT(k.id) FROM perpus_kunjungan k WHERE k.anggota_id=a.id AND DATE(k.waktu_kunjungan) BETWEEN ? AND ?) kunjungan FROM perpus_anggota a LEFT JOIN perpus_tipe_member tm ON tm.id=a.tipe_member_id ORDER BY jumlah_pinjam DESC,kunjungan DESC,a.id LIMIT 500",'ssss',[$from,$to,$from,$to]);foreach($rows as &$r)$r['profile']=sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)($r['pemilik_id']??0),$r);unset($r);
