 $title='Laporan Kunjungan';$description='Rincian kunjungan berdasarkan anggota, waktu, dan sumber pencatatan.';$rows=report_rows($conn,"SELECT k.*,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan FROM perpus_kunjungan k JOIN perpus_anggota a ON a.id=k.anggota_id WHERE DATE(k.waktu_kunjungan) BETWEEN ? AND ? ORDER BY k.waktu_kunjungan DESC LIMIT 1000",'ss',[$from,$to]);foreach($rows as &$r)$r['profile']=sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)($r['pemilik_id']??0),$r);unset($r);
}elseif($report==='denda'){
 $title='Laporan Denda';$description='Denda transaksi, pembayaran, keringanan, pembebasan, dan sisa tunggakan.';$rows=report_rows($conn,"SELECT d.id,d.tanggal_kembali,d.denda,d.denda_status,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul,COALESCE(SUM(x.nominal),0) diselesaikan,GROUP_CONCAT(DISTINCT x.jenis ORDER BY x.jenis SEPARATOR ', ') jenis_penyelesaian FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id JOIN perpus_anggota a ON a.id=p.anggota_id LEFT JOIN perpus_buku b ON b.id=d.buku_id LEFT JOIN perpus_denda_pembayaran x ON x.detail_id=d.id WHERE d.denda>0 AND DATE(d.tanggal_kembali) BETWEEN ? AND ? GROUP BY d.id,d.tanggal_kembali,d.denda,d.denda_status,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul ORDER BY d.tanggal_kembali DESC LIMIT 500",'ss',[$from,$to]);foreach($rows as &$r){$r['profile']=sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)($r['pemilik_id']??0),$r);$r['sisa']=max(0,(float)$r['denda']-(float)$r['diselesaikan']);}unset($r);
}elseif($report==='reservasi'){
 $title='Laporan Reservasi & Inden';$description='Antrean, kesiapan, pengambilan, pembatalan, dan kedaluwarsa reservasi.';$rows=report_rows($conn,"SELECT r.*,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul FROM perpus_reservasi r JOIN perpus_anggota a ON a.id=r.anggota_id JOIN perpus_buku b ON b.id=r.buku_id WHERE DATE(r.tanggal_reservasi) BETWEEN ? AND ? ORDER BY r.tanggal_reservasi DESC LIMIT 500",'ss',[$from,$to]);foreach($rows as &$r)$r['profile']=sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)($r['pemilik_id']??0),$r);unset($r);
