 $title='Laporan Kritik & Saran';$description='Rekap kategori, status tindak lanjut, dan tanggapan layanan.';$rows=report_rows($conn,"SELECT s.*,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan FROM perpus_saran s LEFT JOIN perpus_anggota a ON a.id=s.anggota_id WHERE DATE(s.created_at) BETWEEN ? AND ? ORDER BY s.created_at DESC LIMIT 500",'ss',[$from,$to]);foreach($rows as &$r){$r['profile']=!empty($r['anggota_id'])?sds_perpus_identity_profile($conn,(string)$r['pemilik_tipe'],(int)($r['pemilik_id']??0),$r):['nama'=>$r['nama_pengirim']?:'Anonim','unit'=>'Publik'];}unset($r);
