d><td><?=perpus_h($r['judul'])?></td><td><?=date('d/m/Y H:i',strtotime($r['tanggal_reservasi']))?></td><td><?=$r['tanggal_siap']?date('d/m/Y H:i',strtotime($r['tanggal_siap'])):'-'?><div class="meta"><?=$r['batas_ambil']?date('d/m/Y H:i',strtotime($r['batas_ambil'])):'-'?></div></td><td><?=perpus_h(ucfirst($r['status']))?></td><td><?=perpus_h(ucfirst($r['sumber']))?></td><?php else:$p=$r['profile'];?><td><strong><?=perpus_h($p['nama'])?></strong><div class="meta"><?=perpus_h($r['kontak']?:'Publik')?></div></td><td><?=perpus_h(ucfirst($r['kategori']))?></td><td><?=perpus_h($r['judul'])?><div class="meta"><?=perpus_h(mb_strimwidth((string)$r['pesan'],0,90,'…'))?></div></td><td><?=perpus_h(ucfirst($r['status']))?></td><td><?=perpus_h(mb_strimwidth((string)($r['jawaban']?:'-'),0,90,'…'))?></td><td><?=date('d/m/Y H:i',strtotime($r['created_at']))?></td><?php endif;?></tr><?php endforeach;?></tbody></table></div></div><?php endif;?></div>
